#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10,B=3500;

struct Qry{
    int l,r,t,lca,id;
}qs[N];

struct Opt{
    int x,y;
}opt[N];

int n,m,q,v[N],w[N],c[N],lq,lo,p[2*N];
int fa[N],dep[N],sz[N],son[N],top[N],num,st[N],en[N];
int cnt[N];
bool b[N];
long long res,ans[N];
vector<int> e[N];

void dfs1(int x,int lst){
    fa[x]=lst;
    dep[x]=dep[lst]+1;
    sz[x]=1;
    for(int y:e[x])
        if(y!=lst){
            dfs1(y,x);
            sz[x]+=sz[y];
            if(sz[y]>sz[son[x]])
                son[x]=y;
        }
}

void dfs2(int x,int lst,int topx){
    st[x]=++num;
    p[num]=x;
    top[x]=topx;
    if(son[x])
        dfs2(son[x],x,topx);
    for(int y:e[x])
        if(y!=lst && y!=son[x])
            dfs2(y,x,y);
    en[x]=++num;
    p[num]=x;
}

int LCA(int x,int y){
    while(top[x]!=top[y]){
        if(dep[top[x]]<dep[top[y]])
            swap(x,y);
        x=fa[top[x]];
    }
    return (dep[x]<dep[y]?x:y);
}

bool cmp(Qry x,Qry y){
    if(x.l/B!=y.l/B)
        return x.l/B<y.l/B;
    if(x.r/B!=y.r/B)
        return x.r/B<y.r/B;
    return x.t<y.t;
}

void add(int x){
    b[x]^=1;
    if(!b[x]){
        res-=1ll*v[c[x]]*w[cnt[c[x]]];
        cnt[c[x]]--;
    }else{
        cnt[c[x]]++;
        res+=1ll*v[c[x]]*w[cnt[c[x]]];
    }
}

int main(){
    scanf("%d%d%d",&n,&m,&q);
    for(int i=1;i<=m;i++)
        scanf("%d",&v[i]);
    for(int i=1;i<=n;i++)
        scanf("%d",&w[i]);
    for(int i=1,u,v;i<n;i++){
        scanf("%d%d",&u,&v);
        e[u].push_back(v);
        e[v].push_back(u);
    }
    for(int i=1;i<=n;i++)
        scanf("%d",&c[i]);
    dfs1(1,0);
    dfs2(1,0,1);
    while(q--){
        int op,x,y;
        scanf("%d%d%d",&op,&x,&y);
        if(op==0)
            opt[++lo]={x,y};
        else{
            lq++;
            int lca=LCA(x,y);
            if(st[x]>st[y])
                swap(x,y);
            if(en[y]<=en[x])
                qs[lq].l=st[x]+1,qs[lq].r=st[y];
            else
                qs[lq].l=en[x],qs[lq].r=st[y];
            qs[lq].t=lo;
            qs[lq].lca=lca;
            qs[lq].id=lq;
        }
    }
    sort(qs+1,qs+lq+1,cmp);
    int l=1,r=0,t=0;
    for(int i=1;i<=lq;i++){
        int dl=qs[i].l,dr=qs[i].r,dt=qs[i].t;
        while(t<dt){
            t++;
            if((l<=st[opt[t].x] && st[opt[t].x]<=r)^(l<=en[opt[t].x] && en[opt[t].x]<=r))
                add(opt[t].x);
            swap(opt[t].y,c[opt[t].x]);
            if((l<=st[opt[t].x] && st[opt[t].x]<=r)^(l<=en[opt[t].x] && en[opt[t].x]<=r))
                add(opt[t].x);
        }
        while(t>dt){
            if((l<=st[opt[t].x] && st[opt[t].x]<=r)^(l<=en[opt[t].x] && en[opt[t].x]<=r))
                add(opt[t].x);
            swap(opt[t].y,c[opt[t].x]);
            if((l<=st[opt[t].x] && st[opt[t].x]<=r)^(l<=en[opt[t].x] && en[opt[t].x]<=r))
                add(opt[t].x);
            t--;
        }
        while(l>dl) l--,add(p[l]);
        while(r<dr) r++,add(p[r]);
        while(l<dl) add(p[l]),l++;
        while(r>dr) add(p[r]),r--;
        add(qs[i].lca);
        ans[qs[i].id]=res;
        add(qs[i].lca);
    }
    for(int i=1;i<=lq;i++)
        printf("%lld\n",ans[i]);
    return 0;
}
